#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define MAXN 50000
#define MAXM 100000
// Define the structure for a tree node
typedef struct Node {
    int id;
    struct Node** neighbors;
    int numNeighbors;
} Node;
// Function to check if a number is prime
int isPrime(int num) {
    if (num <= 1) return 0;
    for (int i = 2; i * i <= num; i++) {
        if (num % i == 0) return 0;
    }
    return 1;
}
// Function to calculate the distance between two nodes using BFS
int calculateDistance(Node* start, Node* end) {
    int* visited = (int*)calloc(MAXN, sizeof(int));
    int* queue = (int*)malloc(MAXN * sizeof(int));
    int front = 0, rear = 0;
    queue[rear++] = start->id;
    visited[start->id] = 1;
    int distance = 0;
    while (front < rear) {
        int size = rear - front;
        for (int i = 0; i < size; i++) {
            int currentNode = queue[front++];
            if (currentNode == end->id) return distance;
            for (int j = 0; j < nodes[currentNode].numNeighbors; j++) {
                int neighbor = nodes[currentNode].neighbors[j]->id;
                if (!visited[neighbor]) {
                    queue[rear++] = neighbor;
                    visited[neighbor] = 1;
                }
            }
        }
        distance++;
    }
    free(visited);
    free(queue);
    return -1;
}
// Main function
int main() {
    int N;
    scanf("%d", &N);
    Node* nodes = (Node*)malloc(N * sizeof(Node));
    for (int i = 0; i < N; i++) {
        nodes[i].id = i;
        nodes[i].neighbors = (Node**)malloc(N * sizeof(Node*));
        nodes[i].numNeighbors = 0;
    }
    for (int i = 0; i < N - 1; i++) {
        int a, b;
        scanf("%d %d", &a, &b);
        nodes[a - 1].neighbors[nodes[a - 1].numNeighbors++] = &nodes[b - 1];
        nodes[b - 1].neighbors[nodes[b - 1].numNeighbors++] = &nodes[a - 1];
    }
    int totalPairs = N * (N - 1) / 2;
    int primeDistancePairs = 0;
    for (int i = 0; i < N; i++) {
        for (int j = i + 1; j < N; j++) {
            int distance = calculateDistance(&nodes[i], &nodes[j]);
            if (distance != -1 && isPrime(distance)) primeDistancePairs++;
        }
    }
    printf("%.6f\n", (double)primeDistancePairs / totalPairs);
    for (int i = 0; i < N; i++) {
        free(nodes[i].neighbors);
    }
    free(nodes);
    return 0;
}

