#include <queue>
#include <cmath>
using namespace std;
#define MAXN 50000
// Define the structure for a tree node
struct Node {
    int id;
    vector<Node*> neighbors;
};
// Function to check if a number is prime
bool isPrime(int num) {
    if (num <= 1) return false;
    for (int i = 2; i * i <= num; i++) {
        if (num % i == 0) return false;
    }
    return true;
}
// Function to calculate the distance between two nodes using BFS
int calculateDistance(Node* start, Node* end) {
    vector<bool> visited(MAXN, false);
    queue<Node*> q;
    q.push(start);
    visited[start->id] = true;
    int distance = 0;
    while (!q.empty()) {
        int size = q.size();
        for (int i = 0; i < size; i++) {
            Node* currentNode = q.front();
            q.pop();
            if (currentNode->id == end->id) return distance;
            for (Node* neighbor : currentNode->neighbors) {
                if (!visited[neighbor->id]) {
                    q.push(neighbor);
                    visited[neighbor->id] = true;
                }
            }
        }
        distance++;
    }
    return -1;
}
// Main function
int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int N;
    cin >> N;
    vector<Node> nodes(N);
    for (int i = 0; i < N; i++) {
        nodes[i].id = i;
    }
    for (int i = 0; i < N - 1; i++) {
        int a, b;
        cin >> a >> b;
        nodes[a - 1].neighbors.push_back(&nodes[b - 1]);
        nodes[b - 1].neighbors.push_back(&nodes[a - 1]);
    }
    int totalPairs = N * (N - 1) / 2;
    int primeDistancePairs = 0;
    for (int i = 0; i < N; i++) {
        for (int j = i + 1; j < N; j++) {
            int distance = calculateDistance(&nodes[i], &nodes[j]);
            if (distance != -1 && isPrime(distance)) primeDistancePairs++;
        }
    }
    cout << fixed;
    cout.precision(6);
    cout << (double)primeDistancePairs / totalPairs << endl;
    return 0;
}

