import java.util.Scanner;
import java.util.Queue;
import java.util.LinkedList;
public class Main {
    static final int MAXN = 50000;
    // Define the structure for a tree node
    static class Node {
        int id;
        Node[] neighbors;
        int numNeighbors;
        Node(int id) {
            this.id = id;
            this.neighbors = new Node[MAXN];
            this.numNeighbors = 0;
        }
    }
    // Function to check if a number is prime
    static boolean isPrime(int num) {
        if (num <= 1) return false;
        for (int i = 2; i * i <= num; i++) {
            if (num % i == 0) return false;
        }
        return true;
    }
    // Function to calculate the distance between two nodes using BFS
    static int calculateDistance(Node start, Node end) {
        boolean[] visited = new boolean[MAXN];
        Queue<Node> q = new LinkedList<>();
        q.add(start);
        visited[start.id] = true;
        int distance = 0;
        while (!q.isEmpty()) {
            int size = q.size();
            for (int i = 0; i < size; i++) {
                Node currentNode = q.poll();
                if (currentNode.id == end.id) return distance;
                for (int j = 0; j < currentNode.numNeighbors; j++) {
                    Node neighbor = currentNode.neighbors[j];
                    if (!visited[neighbor.id]) {
                        q.add(neighbor);
                        visited[neighbor.id] = true;
                    }
                }
            }
            distance++;
        }
        return -1;
    }
    // Main function
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        Node[] nodes = new Node[N];
        for (int i = 0; i < N; i++) {
            nodes[i] = new Node(i);
        }
        for (int i = 0; i < N - 1; i++) {
            int a = sc.nextInt() - 1;
            int b = sc.nextInt() - 1;
            nodes[a].neighbors[nodes[a].numNeighbors++] = nodes[b];
            nodes[b].neighbors[nodes[b].numNeighbors++] = nodes[a];
        }
        int totalPairs = N * (N - 1) / 2;
        int primeDistancePairs = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                int distance = calculateDistance(nodes[i], nodes[j]);
                if (distance != -1 && isPrime(distance)) primeDistancePairs++;
            }
        }
        System.out.printf("%.6f\n", (double)primeDistancePairs / totalPairs);
    }
}

