import sys
from collections import deque
# Define the structure for a tree node
class Node:
    def __init__(self, id):
        self.id = id
        self.neighbors = []
# Function to check if a number is prime
def is_prime(num):
    if num <= 1:
        return False
    for i in range(2, int(num ** 0.5) + 1):
        if num % i == 0:
            return False
    return True
# Function to calculate the distance between two nodes using BFS
def calculate_distance(start, end):
    visited = [False] * 50000
    q = deque()
    q.append(start)
    visited[start.id] = True
    distance = 0
    while q:
        size = len(q)
        for _ in range(size):
            current_node = q.popleft()
            if current_node.id == end.id:
                return distance
            for neighbor in current_node.neighbors:
                if not visited[neighbor.id]:
                    q.append(neighbor)
                    visited[neighbor.id] = True
        distance += 1
    return -1
# Main function
if __name__ == '__main__':
    N = int(sys.stdin.readline().strip())
    nodes = [Node(i) for i in range(N)]
    for _ in range(N - 1):
        a, b = map(int, sys.stdin.readline().strip().split())
        nodes[a - 1].neighbors.append(nodes[b - 1])
        nodes[b - 1].neighbors.append(nodes[a - 1])
    total_pairs = N * (N - 1) // 2
    prime_distance_pairs = 0
    for i in range(N):
        for j in range(i + 1, N):
            distance = calculate_distance(nodes[i], nodes[j])
            if distance != -1 and is_prime(distance):
                prime_distance_pairs += 1
    print(f'{prime_distance_pairs / total_pairs:.6f}')

